// 飲食記憶 — app entry. Framework-free. v1 mock-first: FEHD catalogue + album
// memory + recall. No accounts, no real API (vision/LLM mocked).
import "./styles.css";
import type { Catalogue, Memory, Restaurant, Retrieved } from "./types";
import { el, clear, ago } from "./dom";
import { loadCatalogue, searchRestaurants, browseRestaurants, type CatFilter } from "./catalogue";
import {
  allMemories,
  addMemory,
  deleteMemory,
  deleteAllMemories,
  memoryCount,
} from "./memory";
import { suggestDishes, tagsFor } from "./dishes";
import { answerRecall, type RecallResult } from "./recall";
import { hasConsent, grantConsent } from "./consent";

interface UIState {
  cat: Catalogue | null;
  answer: RecallResult | null;
  lastQuery: string;
  catQuery: string;
  catFilter: CatFilter;
}
const state: UIState = {
  cat: null,
  answer: null,
  lastQuery: "",
  catQuery: "",
  catFilter: {},
};

// ---- boot ------------------------------------------------------------------

async function boot(): Promise<void> {
  const app = document.getElementById("app")!;
  app.replaceChildren(el("div", { class: "loading", text: "載入緊…" }));
  try {
    state.cat = await loadCatalogue(import.meta.env.BASE_URL);
  } catch (err) {
    app.replaceChildren(
      el("div", { class: "error" }, "餐廳目錄載入失敗。", el("br"), String(err))
    );
    return;
  }
  if (!hasConsent()) {
    renderConsent();
    return;
  }
  render();
}

// ---- consent gate ----------------------------------------------------------

function renderConsent(): void {
  const app = document.getElementById("app")!;
  clear(app);
  app.appendChild(
    el(
      "div",
      { class: "consent" },
      el("div", { class: "consent-card" },
        el("div", { class: "c-logo", text: "🍜" }),
        el("h1", { text: "飲食記憶" }),
        el("p", { class: "c-lead", text: "你嘅私人飲食記憶 — 去過邊、食過乜、鍾意咩味。" }),
        el("ul", { class: "c-points" },
          el("li", { text: "🔒 記憶只存喺你部機，你完全擁有。" }),
          el("li", { text: "🗑️ 隨時一按刪清晒。" }),
          el("li", { text: "🚫 永遠唔會賣你嘅資料。" })
        ),
        el("p", { class: "c-note", text: "（v1 示範版：全部資料存喺本機，唔會上傳。日後如接 AI 功能，會另外問你同意先。）" }),
        el("button", {
          class: "c-agree",
          text: "明白，開始",
          onclick: () => {
            grantConsent();
            render();
          },
        })
      )
    )
  );
}

// ---- home ------------------------------------------------------------------

function render(): void {
  const app = document.getElementById("app")!;
  clear(app);
  app.appendChild(header());
  app.appendChild(askSection());
  if (state.answer) app.appendChild(answerCard(state.answer));

  const mems = allMemories();
  if (mems.length === 0) app.appendChild(onboardCard());
  app.appendChild(logSection());
  app.appendChild(memoryTimeline(mems));
  app.appendChild(catalogueSection());
  app.appendChild(footer());
}

function header(): HTMLElement {
  const n = memoryCount();
  return el(
    "header",
    { class: "app-header" },
    el("div", { class: "brand" },
      el("span", { class: "logo", text: "🍜" }),
      el("div", {},
        el("h1", { text: "飲食記憶" }),
        el("p", { class: "tagline", text: n > 0 ? `${n} 段記憶 · 生長緊` : "佢記得你食過乜" })
      )
    ),
    el("button", {
      class: "settings-btn",
      text: "⚙︎",
      "aria-label": "設定",
      onclick: openSettings,
    })
  );
}

// ---- ask (recall) ----------------------------------------------------------

function askSection(): HTMLElement {
  const input = el("input", {
    class: "ask-input",
    type: "text",
    placeholder: "問我：今晚食乜好？／上次去譚仔叫咗咩？",
    value: state.lastQuery,
  }) as HTMLInputElement;

  const run = () => {
    const q = input.value.trim();
    if (!q) return;
    state.lastQuery = q;
    state.answer = answerRecall(q, allMemories(), state.cat!);
    render();
  };
  input.addEventListener("keydown", (e) => {
    if ((e as KeyboardEvent).key === "Enter") run();
  });

  const chips = ["今晚食乜好？", "上次去譚仔叫咗咩？", "我鍾意食辣，有咩推介？"].map((c) =>
    el("button", {
      class: "ask-chip",
      text: c,
      onclick: () => {
        input.value = c;
        run();
      },
    })
  );

  return el(
    "section",
    { class: "ask-section" },
    el("p", { class: "ask-lead", text: "問我啖你嘅飲食記憶" }),
    el("div", { class: "ask-row" },
      input,
      el("button", { class: "ask-btn", text: "問", onclick: run })
    ),
    el("div", { class: "ask-chips" }, ...chips)
  );
}

function answerCard(a: RecallResult): HTMLElement {
  const bubble = el("div", { class: "answer-bubble" },
    el("p", { class: "answer-text" },
      ...a.text.split("\n").flatMap((line, i) => (i ? [el("br"), line] : [line]))
    )
  );
  if (a.cited.length) {
    bubble.appendChild(el("p", { class: "cite-label", text: `我睇返 ${a.cited.length} 段相關記憶：` }));
    bubble.appendChild(citedList(a.cited));
  } else {
    bubble.appendChild(el("p", { class: "cite-label muted", text: "（唔會老作 — 冇相關記憶就照直講）" }));
  }
  return el("section", { class: "answer-card kind-" + a.kind },
    el("div", { class: "answer-avatar", text: "🍜" }),
    bubble
  );
}

function citedList(cited: Retrieved[]): HTMLElement {
  const wrap = el("div", { class: "cited" });
  for (const c of cited) {
    wrap.appendChild(
      el("div", { class: "cited-item" },
        el("span", { class: "ci-name", text: c.memory.restaurantName }),
        el("span", { class: "ci-meta", text: `${ago(c.memory.ts)} · ${c.memory.dishes.map((d) => d.name).join("、")}` })
      )
    );
  }
  return wrap;
}

// ---- onboarding: retrospective album scan ----------------------------------

// A hidden <input type=file>. `camera` → capture from camera (single);
// otherwise → photo-library picker (with `multiple`). On mobile, iOS PWAs can't
// read the whole album, so the retrospective entry is an explicit multi-PICK —
// we never pretend to auto-scan everything.
function makeFileInput(
  opts: { multiple?: boolean; camera?: boolean },
  onFiles: (files: FileList) => void
): HTMLInputElement {
  const attrs: Record<string, string | boolean> = {
    type: "file",
    accept: "image/*",
    class: "hidden-file",
  };
  if (opts.multiple) attrs.multiple = true;
  if (opts.camera) attrs.capture = "environment";
  const input = el("input", attrs) as HTMLInputElement;
  input.addEventListener("change", () => {
    if (input.files && input.files.length) onFiles(input.files);
    input.value = ""; // allow re-picking the same file
  });
  return input;
}

function onboardCard(): HTMLElement {
  const albumIn = makeFileInput({ multiple: true }, (f) => runPhotoQueue(f, "album"));
  return el(
    "section",
    { class: "onboard" },
    el("div", { class: "ob-emoji", text: "📸" }),
    el("h2", { text: "揀返你食過嘢嘅相" }),
    el("p", { text: "喺相簿揀幾張食物相，你自己講吓每張係乜、喺邊食 — 我幫你砌返記憶。" }),
    el("button", {
      class: "ob-btn",
      text: "揀相簿相片",
      onclick: () => albumIn.click(),
    }),
    albumIn,
    el("p", { class: "ob-note", text: "你揀邊幾張就處理邊幾張（iOS 讀唔到成個相簿）。冇 AI 認碟 — 你話我知食咗乜，準晒。相只存喺你部機。" })
  );
}

// ---- collection: user self-input (ZERO AI vision) --------------------------

// Distinct past dish names — for autocomplete (own history ranks first).
function pastDishNames(restaurantId?: string): { atRestaurant: string[]; anywhere: string[] } {
  const anywhere: string[] = [];
  const atRestaurant: string[] = [];
  const seenA = new Set<string>();
  const seenR = new Set<string>();
  for (const m of allMemories())
    for (const d of m.dishes) {
      if (!seenA.has(d.name)) { seenA.add(d.name); anywhere.push(d.name); }
      if (restaurantId && m.restaurantId === restaurantId && !seenR.has(d.name)) {
        seenR.add(d.name); atRestaurant.push(d.name);
      }
    }
  return { atRestaurant, anywhere };
}

function logSection(): HTMLElement {
  // Three collection entry points: 相簿 (multi-pick), 影單, 影碟 (camera).
  const albumIn = makeFileInput({ multiple: true }, (f) => runPhotoQueue(f, "album"));
  const receiptIn = makeFileInput({ camera: true }, (f) => runPhotoQueue(f, "receipt"));
  const dishIn = makeFileInput({ camera: true }, (f) => runPhotoQueue(f, "dish"));
  return el(
    "section",
    { class: "log-section" },
    el("h3", { class: "sec-title", text: "記低今餐" }),
    el("div", { class: "log-btns" },
      el("button", { class: "log-btn", text: "📷 揀相簿", onclick: () => albumIn.click() }),
      el("button", { class: "log-btn", text: "🧾 影單", onclick: () => receiptIn.click() }),
      el("button", { class: "log-btn", text: "🍽️ 影碟", onclick: () => dishIn.click() })
    ),
    albumIn, receiptIn, dishIn
  );
}

// Walk a batch of photos, opening the self-input log for each in turn.
function runPhotoQueue(files: FileList, source: Memory["source"]): void {
  const arr = Array.from(files);
  let i = 0;
  let saved = 0;
  const next = () => {
    if (i >= arr.length) {
      if (saved) toast(`加咗 ${saved} 餐入記憶 🎉`);
      render();
      return;
    }
    openLog(source, arr[i], arr.length, i, {
      onSaved: () => { saved++; i++; next(); },
      onSkip: () => { i++; next(); },
    });
  };
  next();
}

// User self-input: type the dish (with autocomplete) + pick the restaurant.
// No AI recognition — the user is the source of truth.
function openLog(
  source: Memory["source"],
  file: File,
  total: number,
  index: number,
  cb: { onSaved: () => void; onSkip: () => void }
): void {
  let closed = false;
  const overlay = el("div", { class: "modal-overlay" });
  const close = (skip: boolean) => {
    if (closed) return;
    closed = true;
    overlay.remove();
    if (skip) cb.onSkip();
  };
  overlay.addEventListener("click", (e) => { if (e.target === overlay) close(true); });

  let picked: Restaurant | null = null;
  let chosenTags: string[] = [];

  // Dish input + autocomplete.
  const dishInput = el("input", {
    class: "log-dish",
    type: "text",
    placeholder: "食咗咩？（打頭幾個字揀）",
    autocomplete: "off",
  }) as HTMLInputElement;
  const dishSug = el("div", { class: "log-sug" });
  const refreshSug = () => {
    clear(dishSug);
    const { atRestaurant, anywhere } = pastDishNames(picked?.id);
    const sugs = suggestDishes(dishInput.value, atRestaurant, anywhere, 8);
    if (!dishInput.value.trim() && !sugs.length) return;
    for (const d of sugs) {
      dishSug.appendChild(
        el("button", {
          class: "sug-chip",
          text: d.name,
          onclick: () => {
            dishInput.value = d.name;
            chosenTags = d.tasteTags;
            clear(dishSug);
          },
        })
      );
    }
  };
  dishInput.addEventListener("input", () => { chosenTags = []; refreshSug(); });
  dishInput.addEventListener("focus", refreshSug);

  // Restaurant search.
  const searchInput = el("input", { class: "log-search", type: "text", placeholder: "喺邊間食？搜尋餐廳…", autocomplete: "off" }) as HTMLInputElement;
  const results = el("div", { class: "log-results" });
  const pickedLabel = el("p", { class: "log-picked", text: "" });
  searchInput.addEventListener("input", () => {
    clear(results);
    for (const r of searchRestaurants(state.cat!, searchInput.value, 6)) {
      results.appendChild(
        el("button", {
          class: "log-result",
          text: `${r.name.tc}　·　${r.area}`,
          onclick: () => {
            picked = r;
            pickedLabel.textContent = `✓ ${r.name.tc}（${r.area}）`;
            clear(results);
            searchInput.value = r.name.tc;
            refreshSug(); // now suggest this restaurant's past dishes first
          },
        })
      );
    }
  });

  const save = el("button", {
    class: "log-save",
    text: "儲入記憶",
    onclick: () => {
      const name = dishInput.value.trim();
      if (!name) { dishInput.focus(); return; }
      if (!picked) { pickedLabel.textContent = "請先揀返間餐廳。"; return; }
      const tags = chosenTags.length ? chosenTags : tagsFor(name);
      addMemory({
        ts: Date.now(),
        restaurantId: picked.id,
        restaurantName: picked.name.tc || picked.name.en,
        area: picked.area,
        dishes: [{ name, tasteTags: tags }],
        tasteTags: tags,
        source,
        confidence: 1, // user-entered = certain
      });
      closed = true;
      overlay.remove();
      cb.onSaved();
    },
  });

  const preview = el("img", { class: "log-preview", src: URL.createObjectURL(file), alt: "" }) as HTMLImageElement;
  preview.addEventListener("load", () => URL.revokeObjectURL(preview.src));

  const title =
    total > 1 ? `第 ${index + 1}/${total} 張 · 呢餐食咗咩？` :
    source === "receipt" ? "記低張單" : "記低呢餐";

  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: () => close(true) }),
      el("h2", { class: "log-title", text: title }),
      preview,
      el("label", { class: "log-lbl", text: "食咗咩" }),
      dishInput,
      dishSug,
      el("label", { class: "log-lbl", text: "邊間餐廳" }),
      searchInput,
      results,
      pickedLabel,
      save,
      total > 1 ? el("button", { class: "log-skip", text: "跳過呢張", onclick: () => close(true) }) : null
    )
  );
  document.body.appendChild(overlay);
  dishInput.focus();
}

// ---- memory timeline -------------------------------------------------------

function memoryTimeline(mems: Memory[]): HTMLElement {
  const section = el("section", { class: "timeline" },
    el("h3", { class: "sec-title", text: `我嘅飲食記憶（${mems.length}）` })
  );
  if (mems.length === 0) {
    section.appendChild(el("p", { class: "empty", text: "未有記憶。掃相簿或者影一餐，就開始生長。" }));
    return section;
  }
  for (const m of mems) {
    section.appendChild(
      el("div", { class: "mem" },
        el("div", { class: "mem-main" },
          el("div", { class: "mem-top" },
            el("span", { class: "mem-name", text: m.restaurantName }),
            el("span", { class: "mem-ago", text: ago(m.ts) })
          ),
          m.area ? el("div", { class: "mem-area", text: "📍 " + m.area }) : null,
          el("div", { class: "mem-dishes", text: m.dishes.map((d) => d.name).join("、") || "—" }),
          el("div", { class: "mem-tags" },
            ...m.tasteTags.slice(0, 5).map((t) => el("span", { class: "mem-tag", text: t })),
            el("span", { class: "mem-src", text: srcLabel(m.source) }),
            m.confidence < 0.75 ? el("span", { class: "mem-fuzzy", text: "大概印象" }) : null
          )
        ),
        el("button", {
          class: "mem-del",
          text: "✕",
          "aria-label": "刪除",
          onclick: () => {
            deleteMemory(m.id);
            render();
          },
        })
      )
    );
  }
  return section;
}

function srcLabel(s: Memory["source"]): string {
  return { album: "📸 相簿", receipt: "🧾 單", dish: "🍽️ 碟", manual: "✍️ 手動" }[s];
}

// ---- catalogue search (基本盤) ---------------------------------------------

const REGIONS: [string, string][] = [["HK", "港島"], ["KLN", "九龍"], ["NT", "新界"]];
const RTYPES: [string, string][] = [["RL", "食肆"], ["RR", "小食"], ["MR", "海鮮舫"]];

function catalogueSection(): HTMLElement {
  const results = el("div", { class: "cat-results" });
  const countLbl = el("p", { class: "cat-count" });
  const input = el("input", {
    class: "cat-input",
    type: "search",
    placeholder: `搜尋全港餐廳（${state.cat?.count ?? 0} 間）`,
    value: state.catQuery,
  }) as HTMLInputElement;

  const renderList = () => {
    clear(results);
    const { items, total } = browseRestaurants(
      state.cat!,
      state.catQuery,
      state.catFilter,
      20
    );
    const filtered = !!(state.catQuery || state.catFilter.region || state.catFilter.type);
    countLbl.textContent = filtered
      ? `${total.toLocaleString()} 間${total > items.length ? `（顯示頭 ${items.length}）` : ""}`
      : `全港 ${(state.cat?.count ?? 0).toLocaleString()} 間 — 搜尋或篩選`;
    if (!filtered) return;
    for (const r of items) {
      results.appendChild(
        el("div", { class: "cat-item" },
          el("span", { class: "cat-name", text: r.name.tc }),
          el("span", { class: "cat-area", text: `${r.area} · ${regionName(r.region)}` })
        )
      );
    }
  };

  let deb: ReturnType<typeof setTimeout> | null = null;
  input.addEventListener("input", () => {
    if (deb) clearTimeout(deb);
    deb = setTimeout(() => { state.catQuery = input.value; renderList(); }, 130);
  });

  const chip = (label: string, active: boolean, onclick: () => void) =>
    el("button", { class: "cat-chip" + (active ? " on" : ""), text: label, onclick });

  const filterRow = el("div", { class: "cat-filters" },
    ...REGIONS.map(([code, name]) =>
      chip(name, state.catFilter.region === code, () => {
        state.catFilter.region = state.catFilter.region === code ? undefined : code;
        renderList();
        filterRow.replaceWith(buildFilterRow());
      })
    ),
    el("span", { class: "cat-sep" }),
    ...RTYPES.map(([code, name]) =>
      chip(name, state.catFilter.type === code, () => {
        state.catFilter.type = state.catFilter.type === code ? undefined : code;
        renderList();
        filterRow.replaceWith(buildFilterRow());
      })
    )
  );
  function buildFilterRow(): HTMLElement {
    // Rebuild to reflect toggled active states.
    const fr = el("div", { class: "cat-filters" },
      ...REGIONS.map(([code, name]) =>
        chip(name, state.catFilter.region === code, () => {
          state.catFilter.region = state.catFilter.region === code ? undefined : code;
          renderList(); fr.replaceWith(buildFilterRow());
        })),
      el("span", { class: "cat-sep" }),
      ...RTYPES.map(([code, name]) =>
        chip(name, state.catFilter.type === code, () => {
          state.catFilter.type = state.catFilter.type === code ? undefined : code;
          renderList(); fr.replaceWith(buildFilterRow());
        }))
    );
    return fr;
  }

  const section = el("section", { class: "cat-section" },
    el("h3", { class: "sec-title", text: "全港餐廳目錄" }),
    input,
    filterRow,
    countLbl,
    results
  );
  renderList();
  return section;
}

function regionName(code: string): string {
  return { HK: "港島", KLN: "九龍", NT: "新界" }[code] ?? code;
}

// ---- settings (privacy: delete all) ----------------------------------------

function openSettings(): void {
  const overlay = el("div", { class: "modal-overlay" });
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) overlay.remove();
  });
  overlay.appendChild(
    el("div", { class: "modal-card" },
      el("button", { class: "modal-close", text: "✕", onclick: () => overlay.remove() }),
      el("h2", { text: "設定 · 私隱" }),
      el("p", { class: "set-line", text: `你有 ${memoryCount()} 段記憶，全部存喺你部機。` }),
      el("p", { class: "set-line muted", text: "你完全擁有呢啲資料。刪除係即時、永久。" }),
      el("button", {
        class: "danger-btn",
        text: "🗑️ 刪除所有記憶",
        onclick: () => {
          if (confirm("確定刪除全部飲食記憶？呢個動作無得復原。")) {
            deleteAllMemories();
            state.answer = null;
            overlay.remove();
            toast("已刪除所有記憶");
            render();
          }
        },
      })
    )
  );
  document.body.appendChild(overlay);
}

function footer(): HTMLElement {
  return el("footer", { class: "app-footer" },
    el("p", { text: "餐廳目錄來源：食環署（FEHD）持牌食肆 open data" }),
    el("p", { class: "src", text: "v1 示範 · AI 功能為 mock（未接真 API）" })
  );
}

// ---- toast -----------------------------------------------------------------

let toastTimer: ReturnType<typeof setTimeout> | null = null;
function toast(text: string): void {
  document.querySelector(".toast")?.remove();
  const node = el("div", { class: "toast", text });
  document.body.appendChild(node);
  if (toastTimer) clearTimeout(toastTimer);
  toastTimer = setTimeout(() => node.remove(), 2600);
}

boot();
