const byName = new Map(VOCAB.map((d) => [d.name, d]));

function norm(s: string): string {
  return (s || "").toLowerCase().replace(/\s+/g, "");
}

/**
 * Autocomplete suggestions for a typed prefix. The user's OWN past dishes (at
 * this restaurant, then anywhere) rank first; the curated vocabulary fills in.
 */
export function suggestDishes(
  prefix: string,
  pastAtRestaurant: string[],
  pastAnywhere: string[],
  limit = 8
): Dish[] {
  const q = norm(prefix);
  const seen = new Set<string>();
  const out: Dish[] = [];
  const push = (name: string) => {
    if (!name || seen.has(name)) return;
    seen.add(name);
    out.push(byName.get(name) ?? { name, tasteTags: [] });
  };
  const match = (name: string) => !q || norm(name).includes(q);

  for (const n of pastAtRestaurant) if (match(n)) push(n);
  for (const n of pastAnywhere) if (match(n)) push(n);
  for (const d of VOCAB) if (match(d.name)) push(d.name);
  return out.slice(0, limit);
}

/** Look up taste tags for a known dish name (empty if user-invented). */
export function tagsFor(name: string): string[] {
  return byName.get(name)?.tasteTags ?? [];
}
